            type: 'line',
            data: {
                labels: inflationData.map(item => item.date),
                datasets: [{
                    label: 'Inflation Rate (%)',
                    data: inflationData.map(item => item.inflationRate),
                    borderColor: 'rgba(255, 99, 132, 1)',
